export const BodyBorderBug = () => {
  const [formValues, setFormValues] = React.useState<{
    clipParent: 'body' | 'blueBox';
    bodyBorder: boolean;
  }>({
    clipParent: 'body',
    bodyBorder: true,
  });
  return (
    <ConfigProvider getPopupContainer={node => node?.parentNode as HTMLElement}>
      <Global
        styles={{
          body: {
            ...(formValues.bodyBorder ? { border: '1px solid red' } : {}),
            height: '100vh',
          },
        }}
      />
      <p>
        这个例子是为了说明在 body border 存在情况下 dom-align 计算 popup 位置时会超出body 1px。此时如果不给子元素 width:
        max-content 还会导致循环计算错误，导致 popup 的宽度一直缩小
      </p>
      <Form initialValues={formValues} onValuesChange={(_, all) => setFormValues(all)}>
        <Form.Item name="bodyBorder" label="body 是否有 border" valuePropName="checked">
          <Switch />
        </Form.Item>
        <Form.Item name="clipParent" label="切换 clip parent">
          <Radio.Group>
            <Radio value="body">body</Radio>
            <Radio value="blueBox">蓝色框</Radio>
          </Radio.Group>
        </Form.Item>
      </Form>
      <div
        css={{
          border: '1px solid blue',
          float: 'right',
          width: 600,
          height: 600,
          display: 'flex',
          flexDirection: 'column',
          alignItems: 'flex-end',
          ...(formValues.clipParent === 'blueBox'
            ? {
                position: 'relative',
                overflow: 'hidden',
              }
            : {}),
        }}
      >
        <div>
          <Tooltip placement="bottom" title={largeDes}>
            <Button>Tooltip</Button>
          </Tooltip>
        </div>
        <div>
          <Popover placement="bottom" title={largeDes}>
            <Button>Popover</Button>
          </Popover>
        </div>
        <div>
          <Popconfirm placement="bottom" title={largeDes}>
            <Button>Popconfirm</Button>
          </Popconfirm>
        </div>
        <div>
          <Dropdown
            placement="bottomCenter"
            overlay={
              <Menu textOverflow={false}>
                <Menu.Item key="a">{largeDes}</Menu.Item>
                <Menu.Item key="b">{largeDes}</Menu.Item>
                <Menu.Item key="c">{largeDes}</Menu.Item>
              </Menu>
            }
          >
            <Button>Dropdown</Button>
          </Dropdown>
        </div>
      </div>
    </ConfigProvider>
  );
};

export const DisabledButton = () => {
  type DisableProp = { disabled?: boolean };
  const renderTooltip = (Component: React.FunctionComponent<DisableProp>) => (
    <Tooltip title="xxxxx" wrapDisabledChildren>
      <Component disabled />
    </Tooltip>
  );
  return (
    <Space direction="vertical">
      <h5>已经不需要使用 wrapDisabledChildren 的表单元素：</h5>
      <Tooltip title="xxxxx">
        <Checkbox disabled />
      </Tooltip>
      <Tooltip title="xxxxx">
        <Switch disabled />
      </Tooltip>

      <h5>还需要使用 wrapDisabledChildren 的表单元素：</h5>

      <Tooltip title="xxxxx" wrapDisabledChildren>
        <IconButton icon={<AddButtonOutlined />} />
      </Tooltip>
      <Tooltip title="xxxxx" wrapDisabledChildren>
        <Button>BUTTON</Button>
      </Tooltip>
      {[Button, Switch].map(renderTooltip)}
      <Tooltip title="xxxxx" wrapDisabledChildren>
        <Input disabled value="3333" />
      </Tooltip>
      <Tooltip title="xxxxx" wrapDisabledChildren>
        <Input.TextArea disabled value="3333" />
      </Tooltip>
      <Tooltip title="xxxxx" wrapDisabledChildren>
        <DatePicker picker="month" disabled />
      </Tooltip>
      <Tooltip title="xxxxx" wrapDisabledChildren>
        <RangePicker picker="month" />
      </Tooltip>

      <Tooltip title="xxxxx">
        <InputNumber disabled value={3333} />
      </Tooltip>
      <Tooltip title="xxxxx" wrapDisabledChildren>
        <Button type="link" disabled href="baidu.com">
          44
        </Button>
      </Tooltip>
      <Tooltip title="xxxxx" wrapDisabledChildren>
        <Button disabled={true}>Hello world!</Button>
      </Tooltip>
      <Tooltip title="xxxxx" wrapDisabledChildren>
        <select disabled={true}>
          <option value="ssss" />
        </select>
      </Tooltip>
      <Tooltip title="xxxxx" wrapDisabledChildren>
        <input disabled={true} />
      </Tooltip>
      <Tooltip title="xxxxx" wrapDisabledChildren>
        <textarea disabled={true} />
      </Tooltip>
      <Tooltip title="xxxxx" wrapDisabledChildren>
        <IconButton icon={<AddButtonOutlined />} disabled />
      </Tooltip>
    </Space>
  );
};

