export const multiLineOverflow = () => {
  const checkOverflow = (ele: Element) => {
    console.log('called: ', ele);
    return ele.scrollHeight > ele.clientHeight;
  };
  return (
    <Tooltip title="overflowed" checkOverflow={checkOverflow}>
      <div
        style={{
          margin: 100,
          width: 200,
          WebkitLineClamp: 2,
          overflow: 'hidden',
          textOverflow: 'ellipsis',
          display: '-webkit-box',
          WebkitBoxOrient: 'vertical',
        }}
      >
        Tooltip will show on mouse enter. Tooltip will show on mouse enter. Tooltip will show on mouse enter. Tooltip
        will show on mouse enter.
      </div>
    </Tooltip>
  );
};
